mapper.insert:
insert into internal_model_providers (
    provider_id, name, base_url, enabled, sort_order, token_id, created_at, updated_at
) values (
    #{providerId}, #{name}, #{baseUrl}, #{enabled}, #{sortOrder}, #{tokenId}, #{createdAt}, #{updatedAt}
)

mapper.delete:
delete from internal_model_providers
where provider_id not in

    #{providerId}

mapper.insert:
insert into internal_model_proxy_settings (
    setting_id, enterprise_openai_auth_token, created_at, updated_at
) values (
    'default', #{authToken}, #{createdAt}, #{updatedAt}
)

insert into internal_model_tokens (
    name, token_value, legacy_key, created_at, updated_at
) values (
    #{name}, #{authToken}, #{legacyKey}, #{createdAt}, #{updatedAt}
)

mapper.update:
update internal_model_tokens
set name = #{name},
    token_value = coalesce(#{authToken}, token_value),
    updated_at = #{updatedAt}
where token_id = #{tokenId}
